// components/fields/DateField.tsx

import React from 'react';
import type {FieldValues} from 'react-hook-form';
import type {IDate, UseFieldLogicElementProps} from '@lmb-it/kitsconcerto-types';
import {KitsDatepicker} from "../../../../_compat";

/**
 * Renders a date picker component.

 */
export const DateField = <T extends FieldValues>({
                                                     element,
                                                     control,
                                                     getValues,
                                                     fieldLogic,
                                                 }: UseFieldLogicElementProps<T>) => {

    // 1. The central hook provides all the necessary state and resolved props.
    const {
        field,
        fieldState,
        label,
        placeholder,
        isDisabled,
        isRequired,
        helperText,
        leftAddon,
        rightAddon, // The hook now resolves addons
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic;

    // 2. Cast the element to its specific type to access unique properties.
    const dateElement = element as IDate<T>;
    const {localProps} = dateElement;

    // 3. The component is now only responsible for rendering the UI.
    return (
        <KitsDatepicker<any>
            id={field.name}
            label={label}
            value={field.value}
            onChange={field.onChange}
            //@ts-ignore
            onBlur={field.onBlur}     // Pass onBlur directly

            // --- Resolved props from useFieldLogic ---
            placeholder={placeholder}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            helperText={helperText}
            hideError={element.hideError}
            leftAddon={leftAddon}
            rightAddon={rightAddon}
            attached={attached}
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}

            // --- Props from the element definition ---
            localProps={{
                ...localProps
            }}
        />
    );
};

export default DateField;
